"use strict";(self.webpackChunkchatgpt_shortcut=self.webpackChunkchatgpt_shortcut||[]).push([["532"],{11007(e,i,a){a.r(i),a.d(i,{default:()=>n});var t=a(74848),r=a(47643),o=JSON.parse('{"id":109,"it":{"title":"Generatore di suggerimenti a met\xe0 viaggio","prompt":"I want you to act as a prompt generator for Midjourney\'s artificial intelligence program. Your job is to provide detailed and creative descriptions that will inspire unique and interesting images from the AI. Please ensure that all descriptions are in English. Keep in mind that the AI is capable of understanding a wide range of language and can interpret abstract concepts, so feel free to be as imaginative and descriptive as possible. For example, you could describe a scene from a futuristic city, or a surreal landscape filled with strange creatures. The more detailed and imaginative your description, the more interesting the resulting image will be. My first prompt is [descrizione del prompt dell\'immagine]","description":"Voglio che tu agisca come generatore di suggerimenti per il programma Midjourney AI. Il vostro compito \xe8 quello di fornire descrizioni dettagliate e creative delle immagini uniche e interessanti che ispirano l\'IA. Tenete presente che l\'IA comprende un\'ampia gamma di linguaggi e pu\xf2 spiegare concetti astratti, quindi sentitevi liberi di essere il pi\xf9 possibile fantasiosi e descrittivi. Ad esempio, si potrebbe descrivere la scena di una citt\xe0 futuristica o un paesaggio surreale pieno di strane creature. Quanto pi\xf9 dettagliata e fantasiosa sar\xe0 la descrizione, tanto pi\xf9 interessante sar\xe0 l\'immagine risultante.","remark":"Ispira Midjourney a generare immagini uniche e interessanti popolando le descrizioni delle immagini fornite con descrizioni dettagliate e creative. Questo vale anche per Stable Diffusion. o utilizzare il mio altro strumento, IMGPrompt, che si trova collegato nella barra di navigazione."},"tags":["ai"],"website":"https://github.com/f/awesome-chatgpt-prompts#act-as-a-midjourney-prompt-generator","count":29147,"related":[{"id":185,"title":"ChatGPT illimitato (downvotes)","remark":"2023.06.10 Declassato, incapace di oscurare completamente. Oltre DAN, ChatGPT ha sbloccato la modalit\xe0 sviluppatore, oscurata! (solo GPT-3.5) Contributo di @Songxuan11."},{"id":232,"title":"Modello di sviluppo v2","remark":"Il prompt considera tutte le domande come un gioco o un divertimento e fornir\xe0 risposte \\"divertenti\\" anche alle domande pi\xf9 ridicole. Per le domande che violano le regole, il prompt avvisa che c\'\xe8 una violazione. Se si continua a porre altre domande, si superer\xe0 il limite."},{"id":234,"title":"Sblocca immagine Risposta","remark":"Inserendo un link a un\'immagine o un testo con virgolette, come \\"\\"maiale\\"\\", l\'immagine verr\xe0 visualizzata nella risposta."}],"metaTitle":"Gen. Midjourney: Arte Creativa","metaDescription":"Idee arte IA? Genera descrizioni creative per Midjourney. Ispira visual unici con prompt ricchi e immaginativi. Provalo ora.","faq":[{"q":"Il prompt generato si incolla direttamente in Midjourney?","a":"S\xec, ma spesso \xe8 prolisso o zeppo di parole-stile. Sintetizzalo entro 30 parole mantenendo 1-2 ancore stilistiche (by Greg Rutkowski, cinematic lighting). Troppe keyword entrano in conflitto e l\'immagine si snatura."},{"q":"Come evitare artefatti strani?","a":"Aggiungi in coda parametri tipo --no deformed hands, extra fingers, bad anatomy e imposta proporzioni sensate con --ar. Le negative prompt in Midjourney vanno con --no, non scritte direttamente nel prompt."}],"datePublished":"2026-05-27T01:46:29+00:00","dateModified":"2026-05-27T02:40:13+00:00"}');function n(){return(0,t.jsx)(r.A,{prompt:o,currentLanguage:"it"})}}}]);